import { agentConfig } from '@mastra/core/agent'
import { indexPdfWorkflow } from './workflows/index_pdf'

export default agentConfig({
  model: 'anthropic/claude-sonnet-4-6',
  workflows: { indexPdfWorkflow },
})

import { LibSQLVector } from '@mastra/libsql'

export const vectorStore = new LibSQLVector({
  id: 'pdf-vectors',
  url: process.env.LIBSQL_URL ?? 'file:./mastra.db',
})

export const PDF_INDEX_NAME = 'pdf_sections'

const EMBEDDING_DIMENSION = 1536

export async function ensureIndex(): Promise<void> {
  const indexes = await vectorStore.listIndexes()
  if (!indexes.includes(PDF_INDEX_NAME)) {
    await vectorStore.createIndex({
      indexName: PDF_INDEX_NAME,
      dimension: EMBEDDING_DIMENSION,
      metric: 'cosine',
    })
  }
}

import { createTool } from '@mastra/core/tools'
import { z } from 'zod'
import { ModelRouterEmbeddingModel } from '@mastra/core/llm'
import { vectorStore, PDF_INDEX_NAME } from '../lib/vector-store'

export default createTool({
  id: 'list_documents',
  description: `List all indexed PDF documents available for quizzing.
Use this tool when:
- The user asks what documents/books are available
- You need to know which documents exist before quizzing
- The user wants to quiz but hasn't specified which document`,
  inputSchema: z.object({}),
  execute: async () => {
    try {
      const embeddingModel = new ModelRouterEmbeddingModel('openai/text-embedding-3-small')
      const { embeddings } = await embeddingModel.doEmbed({ values: ['document'] })

      const results = await vectorStore.query({
        indexName: PDF_INDEX_NAME,
        queryVector: embeddings[0],
        topK: 1000,
      })

      const documentsMap = new Map<
        string,
        {
          documentId: string
          title: string
          totalPages: number
        }
      >()

      for (const result of results) {
        const docId = result.metadata?.documentId as string
        if (docId && !documentsMap.has(docId)) {
          documentsMap.set(docId, {
            documentId: docId,
            title: (result.metadata?.documentTitle as string) || 'Untitled',
            totalPages: (result.metadata?.totalPages as number) || 0,
          })
        }
      }

      const documents = Array.from(documentsMap.values())

      if (documents.length === 0) {
        return {
          documents: [],
          message: 'No documents have been indexed yet. Use the index-pdf workflow to add a PDF.',
        }
      }

      return {
        documents,
        count: documents.length,
      }
    } catch {
      return {
        documents: [],
        message: 'Could not retrieve documents. The vector index may not exist yet.',
      }
    }
  },
})

import { createTool } from '@mastra/core/tools'
import { z } from 'zod'
import { ModelRouterEmbeddingModel } from '@mastra/core/llm'
import { vectorStore, PDF_INDEX_NAME } from '../lib/vector-store'

export default createTool({
  id: 'query_pdf',
  description: `Search PDF content with even distribution across page ranges.

When the user specifies pages (e.g., "pages 50-67"), use pageStart and pageEnd.
The tool retrieves chunks from EACH page in the range, ensuring full coverage.

For general topic searches without page constraints, omit pageStart/pageEnd.`,
  inputSchema: z.object({
    queryText: z.string().describe('Semantic search query describing the content to find'),
    documentId: z.string().optional().describe('Filter by specific document ID (from list-documents tool)'),
    pageStart: z.number().optional().describe('Start of page range (inclusive)'),
    pageEnd: z.number().optional().describe('End of page range (inclusive)'),
  }),
  execute: async (inputData) => {
    const { queryText, documentId, pageStart, pageEnd } = inputData

    const embeddingModel = new ModelRouterEmbeddingModel('openai/text-embedding-3-small')
    const { embeddings } = await embeddingModel.doEmbed({ values: [queryText] })
    const queryVector = embeddings[0]

    if (pageStart === undefined || pageEnd === undefined) {
      const results = await vectorStore.query({
        indexName: PDF_INDEX_NAME,
        queryVector,
        topK: 20,
        filter: documentId ? { documentId } : undefined,
      })

      return {
        chunks: results.map((r) => ({
          text: (r.metadata?.text as string) || '',
          pageNumber: r.metadata?.pageNumber,
          documentTitle: r.metadata?.documentTitle,
          score: r.score,
        })),
        totalChunks: results.length,
      }
    }

    const rangeSize = pageEnd - pageStart + 1
    const thirdSize = Math.ceil(rangeSize / 3)

    const earlyPages: number[] = []
    const middlePages: number[] = []
    const latePages: number[] = []

    for (let page = pageStart; page <= pageEnd; page++) {
      const offset = page - pageStart
      if (offset < thirdSize) {
        earlyPages.push(page)
      } else if (offset < thirdSize * 2) {
        middlePages.push(page)
      } else {
        latePages.push(page)
      }
    }

    const shuffle = <T>(arr: T[]): T[] => {
      const result = [...arr]
      for (let i = result.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1))
        ;[result[i], result[j]] = [result[j], result[i]]
      }
      return result
    }

    const pagesPerSection = 2
    const selectedPages = [
      ...shuffle(earlyPages).slice(0, pagesPerSection),
      ...shuffle(middlePages).slice(0, pagesPerSection),
      ...shuffle(latePages).slice(0, pagesPerSection),
    ]

    const results: Array<{
      text: string
      pageNumber: number
      score: number
    }> = []

    for (const page of selectedPages) {
      try {
        const filter: Record<string, unknown> = { pageNumber: page }
        if (documentId) {
          filter.documentId = documentId
        }

        const pageResults = await vectorStore.query({
          indexName: PDF_INDEX_NAME,
          queryVector,
          topK: 2,
          filter,
        })

        for (const r of pageResults) {
          results.push({
            text: (r.metadata?.text as string) || '',
            pageNumber: page,
            score: r.score || 0,
          })
        }
      } catch {
        // Page may have no chunks
      }
    }

    const shuffledResults = shuffle(results)

    return {
      chunks: shuffledResults,
      pagesCovered: `${pageStart}-${pageEnd}`,
      pagesReturned: selectedPages.sort((a, b) => a - b),
      totalChunks: shuffledResults.length,
      note: 'Stratified sample: chunks from early, middle, AND late pages. Each chunk has a pageNumber - use it for the hint.',
    }
  },
})

import { createStep, createWorkflow } from '@mastra/core/workflows'
import { ModelRouterEmbeddingModel } from '@mastra/core/llm'
import { MDocument } from '@mastra/rag'
import { z } from 'zod'
import { vectorStore, PDF_INDEX_NAME, ensureIndex } from '../lib/vector-store'

const EMBEDDING_DIMENSION = 1536

/**
 * Step 1: Download PDF and extract text from each page
 */
const downloadAndExtractText = createStep({
  id: 'download-and-extract-text',
  description: 'Download PDF from URL and extract text page by page',
  inputSchema: z.object({
    url: z.string().url().describe('URL of the PDF to ingest'),
    documentId: z.string().optional(),
  }),
  outputSchema: z.object({
    documentId: z.string(),
    title: z.string(),
    url: z.string(),
    totalPages: z.number(),
    pages: z.array(
      z.object({
        pageNumber: z.number(),
        content: z.string(),
      }),
    ),
  }),
  execute: async ({ inputData }) => {
    if (!inputData) {
      throw new Error('Input data not found')
    }

    const { url, documentId } = inputData

    const response = await fetch(url)
    if (!response.ok) {
      throw new Error(`Failed to fetch PDF: ${response.status} ${response.statusText}`)
    }

    const arrayBuffer = await response.arrayBuffer()
    const data = new Uint8Array(arrayBuffer)

    // Dynamic import for pdf-parse to avoid issues in some environments
    const { PDFParse } = await import('pdf-parse')
    const parser = new PDFParse({ data })
    const info = await parser.getInfo()
    const totalPages = info.total

    const pages: { pageNumber: number; content: string }[] = []

    for (let i = 1; i <= totalPages; i++) {
      const result = await parser.getText({ partial: [i] })
      if (result.text.trim()) {
        pages.push({
          pageNumber: i,
          content: result.text,
        })
      }
    }

    await parser.destroy()

    const title = info.info?.Title || extractTitleFromUrl(url)
    const docId = documentId || generateDocumentId(url)

    return {
      documentId: docId,
      title: String(title),
      url,
      totalPages,
      pages,
    }
  },
})

/**
 * Step 2: Split pages into smaller chunks for embedding
 */
const splitIntoChunks = createStep({
  id: 'split-into-chunks',
  description: 'Split page text into smaller overlapping chunks',
  inputSchema: z.object({
    documentId: z.string(),
    title: z.string(),
    url: z.string(),
    totalPages: z.number(),
    pages: z.array(z.object({ pageNumber: z.number(), content: z.string() })),
  }),
  outputSchema: z.object({
    documentId: z.string(),
    title: z.string(),
    url: z.string(),
    totalPages: z.number(),
    chunks: z.array(
      z.object({
        text: z.string(),
        metadata: z.record(z.string(), z.any()),
      }),
    ),
  }),
  execute: async ({ inputData: { documentId, title, url, totalPages, pages } }) => {
    const allChunks: { text: string; metadata: Record<string, unknown> }[] = []

    for (const page of pages) {
      const doc = MDocument.fromText(page.content, {
        documentId,
        pageNumber: page.pageNumber,
      })

      const chunks = await doc.chunk({
        strategy: 'recursive',
        maxSize: 512,
        overlap: 50,
      })

      for (const chunk of chunks) {
        allChunks.push({
          text: String(chunk.text),
          metadata: {
            documentId,
            documentTitle: title,
            url,
            pageNumber: page.pageNumber,
            totalPages,
          },
        })
      }
    }

    return {
      documentId,
      title,
      url,
      totalPages,
      chunks: allChunks,
    }
  },
})

/**
 * Step 3: Generate embeddings and store in vector database
 */
const generateAndStoreEmbeddings = createStep({
  id: 'generate-and-store-embeddings',
  description: 'Generate embeddings for each chunk and store in vector database',
  inputSchema: z.object({
    documentId: z.string(),
    title: z.string(),
    url: z.string(),
    totalPages: z.number(),
    chunks: z.array(
      z.object({
        text: z.string(),
        metadata: z.record(z.string(), z.any()),
      }),
    ),
  }),
  outputSchema: z.object({
    documentId: z.string(),
    title: z.string(),
    totalPages: z.number(),
    totalChunks: z.number(),
  }),
  execute: async ({ inputData: { documentId, title, totalPages, chunks } }) => {
    await ensureIndex()

    const embeddingModel = new ModelRouterEmbeddingModel('openai/text-embedding-3-small')
    const texts = chunks.map((c) => c.text)
    const BATCH_SIZE = 2000
    const embeddings: number[][] = []

    for (let i = 0; i < texts.length; i += BATCH_SIZE) {
      const batch = texts.slice(i, i + BATCH_SIZE)
      const result = await embeddingModel.doEmbed({ values: batch })
      embeddings.push(...result.embeddings)
    }

    const metadata = chunks.map((c) => ({
      text: c.text,
      ...c.metadata,
    }))

    try {
      await vectorStore.deleteVectors({
        indexName: PDF_INDEX_NAME,
        filter: { documentId },
      })
    } catch {
      // Index might not exist yet or no vectors to delete
    }

    await vectorStore.upsert({
      indexName: PDF_INDEX_NAME,
      vectors: embeddings,
      metadata,
    })

    return {
      documentId,
      title,
      totalPages,
      totalChunks: chunks.length,
    }
  },
})

export const indexPdfWorkflow = createWorkflow({
  id: 'index-pdf',
  inputSchema: z.object({
    url: z.string().url().describe('URL of the PDF to ingest'),
    documentId: z.string().optional(),
  }),
  outputSchema: z.object({
    documentId: z.string(),
    title: z.string(),
    totalPages: z.number(),
    totalChunks: z.number(),
  }),
})
  .then(downloadAndExtractText)
  .then(splitIntoChunks)
  .then(generateAndStoreEmbeddings)

indexPdfWorkflow.commit()

function extractTitleFromUrl(url: string): string {
  try {
    const pathname = new URL(url).pathname
    const filename = pathname.split('/').pop() || 'document'
    return filename.replace(/\.pdf$/i, '').replace(/[-_]/g, ' ')
  } catch {
    return 'Untitled PDF'
  }
}

function generateDocumentId(url: string): string {
  return `pdf-${Buffer.from(url).toString('base64url').slice(-12)}`
}
